+        .map_err(|err| format!("common dtype failed: {err:?}"))?;
+
+    if matches!(out_dtype, DType::Bool) {
+        out_dtype = DType::Int64;
+    }
+    if matches!(op, ArithmeticOp::Div | ArithmeticOp::Pow) {
+        out_dtype = DType::Float64;
