+fn scalars_equivalent(actual: &Scalar, expected: &Scalar, preserves_nan_missing: bool) -> bool {
+    if (actual.is_nan() && expected.is_nan())
+        || (!preserves_nan_missing && actual.is_missing() && expected.is_missing())
+    {
+        true
+    } else {
+        actual == expected
+    }
+}
