+fn column_arith_preserves_nan_missing(left: &Column, right: &Column, out_dtype: DType) -> bool {
+    !(matches!(out_dtype, DType::Int64)
+        && matches!(left.dtype(), DType::Int64)
+        && matches!(right.dtype(), DType::Int64))
+}
